mapper.select:
SELECT 
FROM pinova.member_login_session
WHERE token_hash = #{tokenHash}
  AND revoked_at IS NULL
  AND expires_at > #{now}
LIMIT 1

mapper.update:
UPDATE pinova.member_login_session
SET last_seen_at = #{now},
    updated_at = #{now},
    updated_by = member_id
WHERE token_hash = #{tokenHash}
  AND revoked_at IS NULL
  AND expires_at > #{now}
  AND last_seen_at <= #{staleBefore}
